    screen.blit(font_big.render("GAME OVER", True, RED),    (280, 260))
    screen.blit(font.render(f"Score: {score}", True, WHITE), (440, 360))
    screen.blit(font.render("R: Restart   Q: Quit", True, WHITE), (350, 410))
    pygame.display.flip()
